import React, { useState, useEffect } from 'react';
import axios from 'axios';

const Careers = () => {
  const [jobs, setJobs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedJob, setSelectedJob] = useState(null);
  const [isFormOpen, setIsFormOpen] = useState(false);

  useEffect(() => {
    const fetchJobs = async () => {
      try {
        const res = await axios.get('http://localhost:5001/api/jobs');
        setJobs(res.data);
        setLoading(false);
      } catch (err) {
        console.error("Fetch error:", err);
        setLoading(false);
      }
    };
    fetchJobs();
  }, []);

  return (
    <div className="bg-white min-h-screen font-sans">
      {/* Header */}
      <section className="pt-32 pb-12 px-8 max-w-7xl mx-auto">
        <h2 className="text-5xl font-black text-gray-950 tracking-tighter">Open Positions</h2>
      </section>

      <section className="px-8 max-w-7xl mx-auto pb-24">
        {/* --- TABLE HEADERS --- */}
        <div className="hidden md:flex items-center px-6 py-4 border-b border-gray-200 bg-gray-50 rounded-t-3xl">
          <div className="w-[40%] text-[10px] font-black uppercase tracking-widest text-gray-400">Job Title</div>
          <div className="w-[20%] text-[10px] font-black uppercase tracking-widest text-gray-400">Location</div>
          <div className="w-[20%] text-[10px] font-black uppercase tracking-widest text-gray-400">Salary</div>
          <div className="w-[20%] text-right text-[10px] font-black uppercase tracking-widest text-gray-400">Action</div>
        </div>

        {/* --- JOBS LIST --- */}
        <div className="border-x border-b border-gray-100 rounded-b-3xl overflow-hidden">
          {loading ? (
            <div className="py-20 text-center text-gray-300 font-bold animate-pulse">LOADING...</div>
          ) : jobs.length > 0 ? (
            jobs.map((job) => (
              <div key={job._id} className="flex flex-col md:flex-row md:items-center px-6 py-8 border-b border-gray-50 last:border-b-0 hover:bg-gray-50 transition-all">

                {/* 1. Title */}
                <div className="w-full md:w-[40%] mb-4 md:mb-0">
                  <span className="md:hidden text-[10px] font-bold text-orange-500 uppercase block mb-1">Title</span>
                  <h3 className="text-xl text-gray-700 font-normal">{job.title}</h3>
                </div>

                {/* 2. Location */}
                <div className="w-full md:w-[20%] mb-4 md:mb-0">
                  <span className="md:hidden text-[10px] font-bold text-orange-500 uppercase block mb-1">Location</span>
                  <p className="text-gray-500 text-sm font-medium">📍 {job.loc}</p>
                </div>

                {/* 3. Salary */}
                <div className="w-full md:w-[20%] mb-4 md:mb-0">
                  <span className="md:hidden text-[10px] font-bold text-orange-500 uppercase block mb-1">Salary</span>
                  <p className="text-gray-400 text-sm font-medium">{job.salary}</p>
                </div>

                {/* 4. Action */}
                <div className="w-full md:w-[20%] text-left md:text-right">
                  <button 
                    onClick={() => { setSelectedJob(job); setIsFormOpen(true); }}
                    className="w-full md:w-auto bg-gray-950 text-white px-8 py-3 rounded-full font-bold text-[11px] uppercase tracking-wider hover:bg-orange-600 transition-all"
                  >
                    Apply Now
                  </button>
                </div>

              </div>
            ))
          ) : (
            <div className="py-20 text-center text-gray-400">No jobs available.</div>
          )}
        </div>
      </section>
    </div>
  );
};

export default Careers;
